import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, Search, Network, Zap, ShieldAlert, CheckCircle2, 
  AlertTriangle, Loader2, Send, ChevronRight, History, 
  Database, Radio, FileSearch, ArrowRightLeft, AlertCircle, Sparkles
} from 'lucide-react';
import { Button, Badge, SectionTitle, Input } from '../components/UI';
import { DiagnosisStep } from './types';

export const DiagnosisAgent: React.FC = () => {
  const [stage, setStage] = useState<'input' | 'processing' | 'conclusion' | 'jump'>('input');
  const [userInput, setUserInput] = useState('');
  const [context, setContext] = useState<any>({
    customer: '安徽省电力公司',
    bizType: '互联网专线',
    instanceId: 'AH-POWER-INET-001',
  });

  const [steps, setSteps] = useState<DiagnosisStep[]>([
    { id: '1', name: '运营商侧专线接口状态', status: 'pending' },
    { id: '2', name: '告警系统核查', status: 'pending' },
    { id: '3', name: '全路路径拨测 (PING/TR069)', status: 'pending' },
    { id: '4', name: '性能指标快照', status: 'pending' }
  ]);

  const [evidence, setEvidence] = useState<any[]>([]);
  const [conclusion, setConclusion] = useState<string>('');
  const [evidenceValues, setEvidenceValues] = useState<any>({});

  const runDiagnosis = async () => {
    setStage('processing');

    // Step 1: 专线接口诊断
    updateStep('1', 'processing');
    await delay(1500);
    const interfaceStatus = 'normal'; // 模拟正常
    if (interfaceStatus === 'error') {
        updateStep('1', 'error', '接口状态异常: 端口物理Down');
        finishDiagnosis('运营商侧物理链路中断，请联系外线查修。');
        return;
    }
    updateStep('1', 'success', '接口状态: Normal');
    addEvidence('接口状态', '运营商侧接口流量正常，无协议状态翻转。');

    // Step 2: 告警查询
    updateStep('2', 'processing');
    await delay(1200);
    updateStep('2', 'success', '无关键性硬件告警');
    addEvidence('告警快照', '查得六端口近1小时内无异常LOS/LOF告警。');

    // Step 3: 分流拨测 (按业务类型)
    updateStep('3', 'processing');
    await delay(2000);

    if (context.bizType === '语音专线') {
        // 模拟语音专线逻辑
        const gatewayOk = false; 
        setEvidenceValues({ gateway: '100% 丢包' });
        updateStep('3', 'error', '企业网关拨测异常');
        setConclusion('移动网络故障，客户专线网关故障');
    } else if (context.bizType === '互联网专线') {
        // 模拟互联网专线组合逻辑
        const pingLoss = 100;
        const gatewayOk = true;
        setEvidenceValues({ ping: '100%', gateway: 'Normal' });

        if (pingLoss === 100 && gatewayOk) {
            updateStep('3', 'success', '组合校验完成');
            setConclusion('客户内网故障，且客户专线正常、路由器故障');
        }
    } else {
        updateStep('3', 'success', '常规拨测正常');
    }
    addEvidence('拨测数据', `PING丢包率: ${evidenceValues.ping || '0%'}, 企业网关实测: ${evidenceValues.gateway || '正常'}`);

    // Step 4: 性能指标
    updateStep('4', 'processing');
    await delay(1000);
    updateStep('4', 'success', '性能快照已导出');
    addEvidence('性能数据', '光功率: -12.4dBm, 带宽利用率: 15%');

    // 收口逻辑
    await delay(800);
    if (context.bizType === '互联网专线') {
        setStage('jump');
    } else {
        setStage('conclusion');
    }
  };

  const updateStep = (id: string, status: any, result?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, result } : s));
  };

  const addEvidence = (label: string, value: string) => {
    setEvidence(prev => [...prev, { label, value }]);
  };

  const finishDiagnosis = (msg: string) => {
    setConclusion(msg);
    setStage('conclusion');
  };

  const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#020617]">
      {stage === 'input' && (
        <div className="flex-1 flex flex-col items-center justify-center p-10 space-y-8 animate-in fade-in zoom-in duration-500">
            <div className="w-24 h-24 rounded-3xl bg-red-500/10 flex items-center justify-center border border-red-500/30 shadow-[0_0_40px_rgba(239,68,68,0.1)]">
                <Activity size={48} className="text-red-500 animate-pulse" />
            </div>
            <div className="text-center max-w-md">
                <h2 className="text-2xl font-black text-white mb-2">业务中断自动诊断</h2>
                <p className="text-slate-500 text-sm">请输入故障现象，智能体将自动编排拨测工具，为您定位故障根因。</p>
            </div>
            <div className="w-full max-w-2xl bg-[#0f172a] border border-slate-800 rounded-3xl p-2 flex gap-2 shadow-2xl focus-within:border-indigo-500/50 transition-all">
                <input 
                    className="flex-1 bg-transparent px-6 py-4 text-white placeholder-slate-600 outline-none"
                    placeholder="例如：合肥电力互联网专线突然访问不了了..."
                    value={userInput}
                    onChange={e => setUserInput(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && runDiagnosis()}
                />
                <Button 
                    className="rounded-2xl px-8 bg-indigo-600 hover:bg-indigo-500 border-none"
                    onClick={runDiagnosis}
                    disabled={!userInput.trim()}
                >
                    发起诊断
                </Button>
            </div>
            <div className="flex gap-3">
                <Badge color="gray" className="cursor-pointer hover:bg-slate-800" onClick={() => setUserInput('江淮汽车语音专线不通')}>语音专线不通</Badge>
                <Badge color="gray" className="cursor-pointer hover:bg-slate-800" onClick={() => setUserInput('省电力互联网业务全断')}>互联网业务全断</Badge>
            </div>
        </div>
      )}

      {(stage === 'processing' || stage === 'jump' || stage === 'conclusion') && (
        <div className="flex-1 flex overflow-hidden animate-in slide-in-from-right-10 duration-500">
            {/* Left: Logic Steps */}
            <div className="w-80 border-r border-slate-800 p-6 space-y-6 bg-[#0f172a]/20">
                <div className="flex items-center justify-between mb-4">
                    <SectionTitle title="诊断流水线" className="mb-0" />
                    {stage === 'processing' && <Loader2 size={16} className="animate-spin text-indigo-500" />}
                </div>

                <div className="space-y-4">
                    {steps.map((step, idx) => (
                        <div key={step.id} className="relative pl-8">
                            <div className={`absolute left-0 top-0.5 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all ${
                                step.status === 'success' ? 'bg-emerald-500 border-emerald-500 text-white' : 
                                (step.status === 'processing' ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-slate-900 border-slate-700 text-slate-600')
                            }`}>
                                {step.status === 'success' ? <CheckCircle2 size={12}/> : (step.status === 'processing' ? <Loader2 size={12} className="animate-spin"/> : <span className="text-[10px]">{idx+1}</span>)}
                            </div>
                            {idx < steps.length - 1 && <div className="absolute left-[10px] top-6 bottom-[-20px] w-px bg-slate-800"></div>}

                            <div className="flex flex-col">
                                <span className={`text-xs font-bold ${step.status === 'processing' ? 'text-indigo-400' : (step.status === 'pending' ? 'text-slate-500' : 'text-slate-200')}`}>{step.name}</span>
                                {step.result && <span className="text-[10px] text-slate-500 mt-1 italic">{step.result}</span>}
                            </div>
                        </div>
                    ))}
                </div>

                <div className="pt-6 border-t border-slate-800 mt-8">
                    <div className="text-[10px] text-slate-500 uppercase font-bold mb-4 tracking-widest">诊断上下文</div>
                    <div className="bg-slate-900/50 rounded-xl p-4 space-y-3 border border-slate-800">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">客户名称</span>
                            <span className="text-[10px] text-slate-300 font-bold">{context.customer}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">业务类型</span>
                            <Badge color="blue" className="scale-75 origin-right">{context.bizType}</Badge>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">实例ID</span>
                            <span className="text-[10px] text-indigo-400 font-mono">{context.instanceId}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right: Evidence & Conclusion */}
            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar flex flex-col gap-8">
                <div className="flex justify-between items-center">
                    <h2 className="text-2xl font-black text-white flex items-center gap-3">
                        <Database size={24} className="text-indigo-500" />
                        诊断证据链
                    </h2>
                    {stage === 'conclusion' && (
                        <Button size="sm" variant="secondary" onClick={() => setStage('input')} icon={<ArrowRightLeft size={14} className="rotate-180"/>}>重新诊断</Button>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-4">
                    {evidence.map((ev, i) => (
                        <div key={i} className="bg-slate-900/40 border border-slate-800 rounded-2xl p-5 hover:border-slate-700 transition-all group">
                            <div className="text-[10px] text-slate-500 font-bold uppercase mb-2 group-hover:text-indigo-400 transition-colors">{ev.label}</div>
                            <div className="text-sm text-slate-200 leading-relaxed font-medium">{ev.value}</div>
                        </div>
                    ))}
                    {evidence.length === 0 && <div className="col-span-2 py-20 text-center text-slate-700 italic">正在采集技术证据...</div>}
                </div>

                {stage === 'conclusion' && (
                    <div className="mt-auto bg-gradient-to-br from-indigo-950/40 to-slate-900 border border-indigo-500/30 rounded-3xl p-8 relative overflow-hidden animate-in zoom-in duration-500 shadow-2xl">
                        <div className="absolute top-0 right-0 p-8 opacity-5"><Sparkles size={80} className="text-indigo-500"/></div>
                        <div className="flex items-center gap-3 mb-4">
                            <div className="p-2 bg-indigo-500 rounded-xl">
                                <ShieldAlert size={20} className="text-white" />
                            </div>
                            <h3 className="text-lg font-black text-white tracking-tight">诊断结论输出</h3>
                        </div>
                        <p className="text-xl font-bold text-indigo-100 leading-snug mb-6">{conclusion}</p>

                        <div className="flex gap-4">
                            <div className="bg-black/20 px-4 py-2 rounded-xl border border-slate-800">
                                <div className="text-[10px] text-slate-500 uppercase">PING 丢包率</div>
                                <div className="text-sm font-bold text-red-400">{evidenceValues.ping || '--'}</div>
                            </div>
                            <div className="bg-black/20 px-4 py-2 rounded-xl border border-slate-800">
                                <div className="text-[10px] text-slate-500 uppercase">网关实测状态</div>
                                <div className="text-sm font-bold text-emerald-400">{evidenceValues.gateway || '--'}</div>
                            </div>
                        </div>

                        <div className="mt-8 pt-6 border-t border-slate-800 flex justify-between items-center">
                            <span className="text-xs text-slate-500">以上结论基于编排接口及自动化拨测工具生成，准确率 98%</span>
                            <Button className="bg-indigo-600 hover:bg-indigo-500 border-none">转入人工处理</Button>
                        </div>
                    </div>
                )}

                {stage === 'jump' && (
                    <div className="mt-auto bg-blue-900/10 border border-blue-500/30 rounded-3xl p-10 text-center space-y-6 animate-in slide-in-from-bottom-10 duration-700 shadow-2xl">
                        <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center mx-auto ring-4 ring-blue-500/20">
                            <ArrowRightLeft size={32} className="text-blue-400 animate-pulse" />
                        </div>
                        <div>
                            <h3 className="text-2xl font-black text-white">已进入互联网业务质差定界流程</h3>
                            <p className="text-slate-500 mt-2">诊断检测到“互联网专线”业务且基本连通正常。系统正在携带已采集证据跳转至多维定界系统...</p>
                        </div>
                        <div className="flex items-center justify-center gap-3">
                            <Loader2 size={16} className="animate-spin text-blue-500" />
                            <span className="text-xs text-blue-400 font-bold tracking-widest uppercase">证据同步中: 接口/告警/PING/网关/配置</span>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { ReactNode, useState, useRef, useEffect } from 'react';
import { X, Check, AlertCircle, ChevronDown, Search, ChevronLeft, ChevronRight, ArrowUp, ArrowDown, Plus, Trash2, ArrowUpDown } from 'lucide-react';

// --- Colors ---
// Using Tailwind standard palette, keeping in mind the dark blue enterprise theme.
// Primary: blue-600
// Bg: slate-900 / slate-800
// Border: slate-700

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ variant = 'primary', size = 'md', icon, children, className, ...props }) => {
  const baseStyle = "inline-flex items-center justify-center rounded transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white focus:ring-blue-500 shadow-sm",
    secondary: "bg-slate-800 hover:bg-slate-700 text-slate-200 focus:ring-slate-500 border border-slate-600",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-300 hover:text-white"
  };

  const sizes = {
    sm: "px-2 py-1 text-xs",
    md: "px-4 py-1.5 text-sm", // Adjusted height slightly
    lg: "px-6 py-3 text-base"
  };

  return (
    <button className={`${baseStyle} ${variants[variant]} ${sizes[size]} ${className || ''}`} {...props}>
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

export const Switch: React.FC<{ checked: boolean; onChange: (checked: boolean) => void; disabled?: boolean }> = ({ checked, onChange, disabled }) => {
  return (
    <button 
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      className={`relative inline-flex h-5 w-9 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900 ${checked ? 'bg-emerald-500' : 'bg-red-500'} ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <span className="sr-only">Use setting</span>
      <span
        aria-hidden="true"
        className={`pointer-events-none inline-block h-4 w-4 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${checked ? 'translate-x-4' : 'translate-x-0'}`}
      />
    </button>
  );
};

// Enhanced Card to support flex-1 children for scrolling
export const Card: React.FC<{ children: ReactNode; title?: string; className?: string; action?: ReactNode; bodyClassName?: string }> = ({ children, title, className, action, bodyClassName }) => (
  <div className={`bg-slate-800/40 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm flex flex-col ${className || ''}`}>
    {title && (
      <div className="px-5 py-3 border-b border-slate-700/50 flex justify-between items-center bg-slate-900/30 rounded-t-lg shrink-0">
        <h3 className="font-semibold text-slate-100 flex items-center gap-2">
           <div className="w-1 h-4 bg-blue-500 rounded-full"></div>
           {title}
        </h3>
        {action && <div>{action}</div>}
      </div>
    )}
    {/* Body: flex-1 min-h-0 allows nested scroll containers to work properly */}
    <div className={`p-5 flex-1 min-h-0 flex flex-col ${bodyClassName || ''}`}>{children}</div>
  </div>
);

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: ReactNode;
  footer?: ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, footer, size = 'md' }) => {
  if (!isOpen) return null;

  const sizes = {
    sm: 'max-w-md',
    md: 'max-w-xl',
    lg: 'max-w-4xl', // Widened for better grid layout
    xl: 'max-w-6xl'
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm transition-opacity animate-in fade-in duration-200">
      <div className={`bg-[#0b1121] border border-slate-700 w-full ${sizes[size]} rounded-lg shadow-2xl flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200`}>
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-700 bg-[#0f172a] rounded-t-lg shrink-0">
          <h2 className="text-lg font-bold text-white tracking-wide">{title}</h2>
