interface ColumnConfigProps {
  isOpen: boolean;
  onClose: () => void;
  allColumns: { key: string; header: string }[];
  currentOrder: string[]; 
  onSave: (newOrder: string[]) => void;
}

export const ColumnConfigDialog: React.FC<ColumnConfigProps> = ({ isOpen, onClose, allColumns, currentOrder, onSave }) => {
  const [orderedKeys, setOrderedKeys] = useState(currentOrder);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
      if (isOpen) setOrderedKeys(currentOrder);
  }, [isOpen, currentOrder]);

  // Filter left list
  const filteredAllColumns = allColumns.filter(col => 
      col.header.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleToggle = (key: string) => {
      if (orderedKeys.includes(key)) {
          setOrderedKeys(orderedKeys.filter(k => k !== key));
      } else {
          setOrderedKeys([...orderedKeys, key]);
      }
  };

  const handleSelectAll = () => {
      const visibleKeys = filteredAllColumns.map(c => c.key);
      const allSelected = visibleKeys.every(k => orderedKeys.includes(k));

      if (allSelected) {
          // Deselect visible
          setOrderedKeys(orderedKeys.filter(k => !visibleKeys.includes(k)));
      } else {
          // Select visible (append missing)
          const newKeys = [...orderedKeys];
          visibleKeys.forEach(k => {
              if (!newKeys.includes(k)) newKeys.push(k);
          });
          setOrderedKeys(newKeys);
      }
  };

  const handleClear = () => {
      setOrderedKeys([]);
  };

  const move = (index: number, direction: -1 | 1) => {
      const newOrder = [...orderedKeys];
      if (index + direction < 0 || index + direction >= newOrder.length) return;
      const [item] = newOrder.splice(index, 1);
      newOrder.splice(index + direction, 0, item);
      setOrderedKeys(newOrder);
  };

  // Right side list objects
  const visibleColumns = orderedKeys.map(k => allColumns.find(c => c.key === k)).filter(Boolean) as typeof allColumns;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="表格列配置" size="lg" 
      footer={
        <div className="flex justify-center gap-4 w-full">
           <Button className="bg-blue-600 hover:bg-blue-500 text-white w-32 border-none" onClick={() => { onSave(orderedKeys); onClose(); }}>确认</Button>
           <Button className="bg-amber-500 hover:bg-amber-600 text-white border-none w-32" onClick={onClose}>取消</Button>
        </div>
      }
    >
      <div className="flex flex-col h-[500px]">
          {/* Search */}
          <div className="mb-4 relative">
              <input 
                  type="text" 
                  placeholder="请输入内容" 
                  className="w-full bg-[#0f172a] border border-slate-700 rounded-md py-2 pl-4 pr-10 text-sm text-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
              />
              <Search className="absolute right-3 top-2.5 text-slate-500" size={16} />
          </div>

          <div className="flex flex-1 gap-6 min-h-0">
              {/* Left Panel */}
              <div className="flex-1 flex flex-col">
                  <div className="flex justify-between items-center mb-3 text-sm px-1">
                      <span className="text-slate-400">可配置列: {allColumns.length}</span>
                      <button onClick={handleSelectAll} className="text-blue-400 hover:text-blue-300 font-medium">全选</button>
                  </div>
                  <div className="flex-1 border border-slate-700/50 rounded-lg overflow-y-auto custom-scrollbar p-2 bg-[#0f172a]/50">
                      {filteredAllColumns.map(col => {
                          const isChecked = orderedKeys.includes(col.key);
                          return (
                              <div 
                                  key={col.key} 
                                  className={`flex items-center p-2.5 rounded cursor-pointer hover:bg-slate-800 transition-colors mb-1 ${isChecked ? 'bg-blue-900/10' : ''}`}
                                  onClick={() => handleToggle(col.key)}
                              >
                                  <div className={`w-4 h-4 rounded-full border flex items-center justify-center mr-3 transition-colors shrink-0 ${isChecked ? 'bg-blue-600 border-blue-600' : 'border-slate-600 bg-slate-900'}`}>
                                      {isChecked && <Check size={10} className="text-white" />}
                                  </div>
                                  <span className={isChecked ? 'text-blue-100 font-medium' : 'text-slate-400'}>{col.header}</span>
                              </div>
                          );
                      })}
                  </div>
              </div>

              {/* Right Panel */}
              <div className="flex-1 flex flex-col">
                  <div className="flex justify-between items-center mb-3 text-sm px-1">
                      <span className="text-slate-400">已选列数: {orderedKeys.length}</span>
                      <button onClick={handleClear} className="text-blue-400 hover:text-blue-300 font-medium">清空</button>
                  </div>
                  <div className="flex-1 border border-slate-700/50 rounded-lg overflow-y-auto custom-scrollbar p-2 bg-[#0f172a]/50">
                      {visibleColumns.map((col, idx) => (
                          <div key={col.key} className="flex items-center justify-between p-2.5 mb-1.5 rounded bg-slate-800/80 border border-transparent hover:border-blue-500/50 group transition-all">
                              <div className="flex items-center gap-3">
                                  <ArrowUpDown size={14} className="text-blue-500 cursor-grab active:cursor-grabbing opacity-70" />
                                  <span className="text-slate-200 text-sm">{col.header}</span>
                              </div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button 
                                      className="p-1 text-slate-500 hover:text-blue-400 disabled:opacity-30 transition-colors" 
                                      onClick={() => move(idx, -1)} 
                                      disabled={idx === 0}
                                      title="上移"
                                  >
                                      <ArrowUp size={14} />
                                  </button>
                                  <button 
                                      className="p-1 text-slate-500 hover:text-blue-400 disabled:opacity-30 transition-colors" 
                                      onClick={() => move(idx, 1)} 
                                      disabled={idx === visibleColumns.length - 1}
                                      title="下移"
                                  >
                                      <ArrowDown size={14} />
                                  </button>
                                  <button 
                                      className="p-1 text-slate-500 hover:text-red-400 ml-1 transition-colors" 
                                      onClick={() => handleToggle(col.key)}
                                      title="移除"
                                  >
                                      <Trash2 size={14} />
                                  </button>
                              </div>
                          </div>
                      ))}
                      {visibleColumns.length === 0 && (
                          <div className="h-full flex flex-col items-center justify-center text-slate-500 text-xs">
                              <span className="opacity-50">暂无已选列</span>
                          </div>
                      )}
                  </div>
              </div>
          </div>
      </div>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, Search, Network, Zap, ShieldAlert, CheckCircle2, 
  AlertTriangle, Loader2, Send, ChevronRight, History, 
  Database, Radio, FileSearch, ArrowRightLeft, AlertCircle, Sparkles
} from 'lucide-react';
import { Button, Badge, SectionTitle, Input } from '../components/UI';
import { DiagnosisStep } from './types';

export const DiagnosisAgent: React.FC = () => {
  const [stage, setStage] = useState<'input' | 'processing' | 'conclusion' | 'jump'>('input');
  const [userInput, setUserInput] = useState('');
  const [context, setContext] = useState<any>({
    customer: '安徽省电力公司',
    bizType: '互联网专线',
    instanceId: 'AH-POWER-INET-001',
  });

  const [steps, setSteps] = useState<DiagnosisStep[]>([
    { id: '1', name: '运营商侧专线接口状态', status: 'pending' },
    { id: '2', name: '告警系统核查', status: 'pending' },
    { id: '3', name: '全路路径拨测 (PING/TR069)', status: 'pending' },
    { id: '4', name: '性能指标快照', status: 'pending' }
  ]);

  const [evidence, setEvidence] = useState<any[]>([]);
  const [conclusion, setConclusion] = useState<string>('');
  const [evidenceValues, setEvidenceValues] = useState<any>({});

  const runDiagnosis = async () => {
    setStage('processing');

    // Step 1: 专线接口诊断
    updateStep('1', 'processing');
    await delay(1500);
    // Fix: Explicitly type interfaceStatus as string to allow comparison with 'error' literal value
    const interfaceStatus: string = 'normal'; // 模拟正常
    if (interfaceStatus === 'error') {
        updateStep('1', 'error', '接口状态异常: 端口物理Down');
        finishDiagnosis('运营商侧物理链路中断，请联系外线查修。');
        return;
    }
    updateStep('1', 'success', '接口状态: Normal');
    addEvidence('接口状态', '运营商侧接口流量正常，无协议状态翻转。');

    // Step 2: 告警查询
    updateStep('2', 'processing');
    await delay(1200);
    updateStep('2', 'success', '无关键性硬件告警');
    addEvidence('告警快照', '查得六端口近1小时内无异常LOS/LOF告警。');

    // Step 3: 分流拨测 (按业务类型)
    updateStep('3', 'processing');
    await delay(2000);

    if (context.bizType === '语音专线') {
        // 模拟语音专线逻辑
        const gatewayOk = false; 
        setEvidenceValues({ gateway: '100% 丢包' });
        updateStep('3', 'error', '企业网关拨测异常');
        setConclusion('移动网络故障，客户专线网关故障');
    } else if (context.bizType === '互联网专线') {
        // 模拟互联网专线组合逻辑
        const pingLoss = 100;
        const gatewayOk = true;
        setEvidenceValues({ ping: '100%', gateway: 'Normal' });

        if (pingLoss === 100 && gatewayOk) {
            updateStep('3', 'success', '组合校验完成');
            setConclusion('客户内网故障，且客户专线正常、路由器故障');
        }
    } else {
        updateStep('3', 'success', '常规拨测正常');
    }
    addEvidence('拨测数据', `PING丢包率: ${evidenceValues.ping || '0%'}, 企业网关实测: ${evidenceValues.gateway || '正常'}`);

    // Step 4: 性能指标
    updateStep('4', 'processing');
    await delay(1000);
    updateStep('4', 'success', '性能快照已导出');
    addEvidence('性能数据', '光功率: -12.4dBm, 带宽利用率: 15%');

    // 收口逻辑
    await delay(800);
    if (context.bizType === '互联网专线') {
        setStage('jump');
    } else {
        setStage('conclusion');
    }
  };

  const updateStep = (id: string, status: any, result?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, result } : s));
  };

  const addEvidence = (label: string, value: string) => {
    setEvidence(prev => [...prev, { label, value }]);
  };

  const finishDiagnosis = (msg: string) => {
    setConclusion(msg);
    setStage('conclusion');
  };

  const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#020617]">
      {stage === 'input' && (
        <div className="flex-1 flex flex-col items-center justify-center p-10 space-y-8 animate-in fade-in zoom-in duration-500">
            <div className="w-24 h-24 rounded-3xl bg-red-500/10 flex items-center justify-center border border-red-500/30 shadow-[0_0_40px_rgba(239,68,68,0.1)]">
                <Activity size={48} className="text-red-500 animate-pulse" />
            </div>
            <div className="text-center max-w-md">
                <h2 className="text-2xl font-black text-white mb-2">业务中断自动诊断</h2>
                <p className="text-slate-500 text-sm">请输入故障现象，智能体将自动编排拨测工具，为您定位故障根因。</p>
            </div>
            <div className="w-full max-w-2xl bg-[#0f172a] border border-slate-800 rounded-3xl p-2 flex gap-2 shadow-2xl focus-within:border-indigo-500/50 transition-all">
                <input 
                    className="flex-1 bg-transparent px-6 py-4 text-white placeholder-slate-600 outline-none"
                    placeholder="例如：合肥电力互联网专线突然访问不了了..."
                    value={userInput}
                    onChange={e => setUserInput(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && runDiagnosis()}
                />
                <Button 
                    className="rounded-2xl px-8 bg-indigo-600 hover:bg-indigo-500 border-none"
                    onClick={runDiagnosis}
                    disabled={!userInput.trim()}
                >
                    发起诊断
                </Button>
            </div>
            <div className="flex gap-3">
                {/* Fix: Badge component now supports onClick via updated definition in components/UI.tsx */}
                <Badge color="gray" className="cursor-pointer hover:bg-slate-800" onClick={() => setUserInput('江淮汽车语音专线不通')}>语音专线不通</Badge>
                <Badge color="gray" className="cursor-pointer hover:bg-slate-800" onClick={() => setUserInput('省电力互联网业务全断')}>互联网业务全断</Badge>
            </div>
        </div>
      )}

      {(stage === 'processing' || stage === 'jump' || stage === 'conclusion') && (
        <div className="flex-1 flex overflow-hidden animate-in slide-in-from-right-10 duration-500">
            {/* Left: Logic Steps */}
            <div className="w-80 border-r border-slate-800 p-6 space-y-6 bg-[#0f172a]/20">
                <div className="flex items-center justify-between mb-4">
                    <SectionTitle title="诊断流水线" className="mb-0" />
                    {stage === 'processing' && <Loader2 size={16} className="animate-spin text-indigo-500" />}
                </div>

                <div className="space-y-4">
                    {steps.map((step, idx) => (
                        <div key={step.id} className="relative pl-8">
                            <div className={`absolute left-0 top-0.5 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all ${
                                step.status === 'success' ? 'bg-emerald-500 border-emerald-500 text-white' : 
                                (step.status === 'processing' ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-slate-900 border-slate-700 text-slate-600')
                            }`}>
                                {step.status === 'success' ? <CheckCircle2 size={12}/> : (step.status === 'processing' ? <Loader2 size={12} className="animate-spin"/> : <span className="text-[10px]">{idx+1}</span>)}
                            </div>
                            {idx < steps.length - 1 && <div className="absolute left-[10px] top-6 bottom-[-20px] w-px bg-slate-800"></div>}

                            <div className="flex flex-col">
                                <span className={`text-xs font-bold ${step.status === 'processing' ? 'text-indigo-400' : (step.status === 'pending' ? 'text-slate-500' : 'text-slate-200')}`}>{step.name}</span>
                                {step.result && <span className="text-[10px] text-slate-500 mt-1 italic">{step.result}</span>}
                            </div>
                        </div>
                    ))}
                </div>

                <div className="pt-6 border-t border-slate-800 mt-8">
                    <div className="text-[10px] text-slate-500 uppercase font-bold mb-4 tracking-widest">诊断上下文</div>
                    <div className="bg-slate-900/50 rounded-xl p-4 space-y-3 border border-slate-800">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">客户名称</span>
                            <span className="text-[10px] text-slate-300 font-bold">{context.customer}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">业务类型</span>
                            <Badge color="blue" className="scale-75 origin-right">{context.bizType}</Badge>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">实例ID</span>
                            <span className="text-[10px] text-indigo-400 font-mono">{context.instanceId}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right: Evidence & Conclusion */}
            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar flex flex-col gap-8">
