                                        <div className="whitespace-pre-wrap">{msg.content}</div>
                                    </div>
                                    <div className={`text-[10px] text-slate-600 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>{msg.timestamp}</div>
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className="flex gap-4 max-w-[85%]">
                                <div className="w-9 h-9 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center shrink-0">
                                    <Loader2 className="animate-spin text-indigo-500" size={18} />
                                </div>
                                <div className="bg-[#1e293b]/50 p-4 rounded-2xl rounded-tl-none border border-slate-800 flex gap-1 items-center h-10">
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Chat Input */}
                <div className="p-6 border-t border-slate-800 bg-[#0f172a]/50 shrink-0">
                    <div className="max-w-4xl mx-auto flex gap-4">
                        <div className="flex-1 relative group">
                            <div className="absolute left-3 top-1/2 -translate-y-1/2 flex items-center gap-2 opacity-50 group-focus-within:opacity-100 transition-opacity">
                                <button className="p-1 hover:text-indigo-400"><Paperclip size={16}/></button>
                            </div>
                            <input 
                                className="w-full bg-[#1e293b] border border-slate-700 rounded-2xl py-4 pl-12 pr-4 text-sm text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all shadow-inner"
                                placeholder={isHuman ? "输入消息告知二线专家..." : "询问 AI 管家或输入排障需求..."}
                                value={inputValue}
                                onChange={e => setInputValue(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleSend()}
                            />
                        </div>
                        <Button 
                            onClick={handleSend} 
                            disabled={!inputValue.trim() || isLoading}
                            className="rounded-2xl w-14 h-14 p-0 bg-indigo-600 hover:bg-indigo-500 border-none shadow-xl shadow-indigo-900/40 shrink-0"
                        >
                            <Send size={20} />
                        </Button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, Search, Network, Zap, ShieldAlert, CheckCircle2, 
  AlertTriangle, Loader2, Send, ChevronRight, History, 
  Database, Radio, FileSearch, ArrowRightLeft, AlertCircle, Sparkles,
  Pause, Play, SkipForward, ArrowLeft, RefreshCcw
} from 'lucide-react';
import { Button, Badge, SectionTitle, Input } from '../components/UI';
import { DiagnosisStep } from './types';

export const DiagnosisAgent: React.FC = () => {
  const [stage, setStage] = useState<'input' | 'processing' | 'conclusion' | 'jump'>('input');
  const [isPaused, setIsPaused] = useState(false);
  const [simMode, setSimMode] = useState<'normal' | 'cut' | 'voice' | 'quality'>('normal');
  const [currentStepIdx, setCurrentStepIdx] = useState(-1);
  const [userInput, setUserInput] = useState('');
  const [context, setContext] = useState<any>({
    customer: '安徽省电力公司',
    bizType: '互联网专线',
    instanceId: 'AH-POWER-INET-001',
  });

  const [steps, setSteps] = useState<DiagnosisStep[]>([
    { id: '1', name: '运营商侧物理接口探测', status: 'pending' },
    { id: '2', name: '全路路径告警核查', status: 'pending' },
    { id: '3', name: '业务层面分流拨测 (ICMP/SIP)', status: 'pending' },
    { id: '4', name: '端到端性能快照导出', status: 'pending' }
  ]);

  const [evidence, setEvidence] = useState<any[]>([]);
  const [conclusion, setConclusion] = useState<string>('');
  const [evidenceValues, setEvidenceValues] = useState<any>({});

  // 核心控制逻辑
  useEffect(() => {
    let timer: any;
    if (stage === 'processing' && !isPaused && currentStepIdx < steps.length) {
        timer = setTimeout(() => {
            executeNextStep();
        }, 1500);
    }
    return () => clearTimeout(timer);
  }, [stage, isPaused, currentStepIdx]);

  const executeNextStep = async () => {
      const idx = currentStepIdx === -1 ? 0 : currentStepIdx;
      if (idx >= steps.length) return;

      const step = steps[idx];
      updateStep(step.id, 'processing');

      // 模拟每步逻辑
      if (idx === 0) {
          if (simMode === 'cut') {
              updateStep(step.id, 'error', '端口状态: DOWN (LOS告警)');
              finishDiagnosis('运营商侧外线物理中断。检测到物理层信号丢失，已自动派单至线路维保组。');
              return;
          }
          updateStep(step.id, 'success', '接口状态: NORMAL');
          addEvidence('接口探测', '上联端口 A/B 路负载均衡正常，未见物理翻转。');
      } else if (idx === 1) {
          updateStep(step.id, 'success', '全路告警核查完成');
          addEvidence('告警分析', '查得近1小时内无异常掉电或高阶路径LOS告警。');
      } else if (idx === 2) {
          if (context.bizType === '语音专线') {
              updateStep(step.id, 'error', '企业侧 PBX 拨测超时');
              setEvidenceValues({ sip: 'Auth Failed', gateway: 'Unreachable' });
              addEvidence('业务拨测', 'SIP 信令握手失败，对端网关 10.224.1.5 无响应。');
              finishDiagnosis('语音专线业务异常。定位为客户侧企业网关（PBX）宕机或配置丢失，请检查本地供电及配置态。');
              return;
          }
          // 互联网专线质量问题
          if (simMode === 'quality') {
              updateStep(step.id, 'success', 'PING 丢包率: 15%');
              setEvidenceValues({ ping: '15%', gateway: 'Normal' });
              addEvidence('质量拨测', '关键路径存在突发性丢包，物理链路通畅但业务质差。');
          } else {
              updateStep(step.id, 'success', '拨测正常');
              addEvidence('业务拨测', 'PING丢包率 0%，时延 8ms。');
          }
      } else if (idx === 3) {
          updateStep(step.id, 'success', '性能指标导出成功');
          addEvidence('性能快照', '光功率: -14.2dBm, 流量峰值: 45Mbps。');

          // 最后流转判断
          if (context.bizType === '互联网专线' && simMode === 'quality') {
              setStage('jump');
          } else {
              finishDiagnosis('业务运行基本正常。未发现明显故障根因，建议联系二线专家进行更深层次的数据流包头分析。');
          }
          return;
      }

      setCurrentStepIdx(idx + 1);
  };

  const handleStart = (mode: 'normal' | 'cut' | 'voice' | 'quality') => {
    setSimMode(mode);
    setContext({
        customer: mode === 'voice' ? '江淮汽车集团' : '安徽省电力公司',
        bizType: mode === 'voice' ? '语音专线' : '互联网专线',
        instanceId: mode === 'voice' ? 'JAC-VOICE-102' : 'AH-POWER-INET-001'
    });
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending', result: undefined })));
    setEvidence([]);
    setEvidenceValues({});
    setCurrentStepIdx(0);
    setStage('processing');
    setIsPaused(false);
  };

  const updateStep = (id: string, status: any, result?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, result } : s));
  };

  const addEvidence = (label: string, value: string) => {
    setEvidence(prev => [...prev, { label, value }]);
  };

  const finishDiagnosis = (msg: string) => {
    setConclusion(msg);
    setStage('conclusion');
  };

  const resetAll = () => {
    setStage('input');
    setSimMode('normal');
    setCurrentStepIdx(-1);
    setEvidence([]);
  };

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#020617]">
      {stage === 'input' && (
        <div className="flex-1 flex flex-col items-center justify-center p-10 space-y-10 animate-in fade-in zoom-in duration-500">
            <div className="w-24 h-24 rounded-3xl bg-red-500/10 flex items-center justify-center border border-red-500/30 shadow-[0_0_40px_rgba(239,68,68,0.1)]">
                <Activity size={48} className="text-red-500 animate-pulse" />
            </div>
            <div className="text-center max-w-md">
                <h2 className="text-2xl font-black text-white mb-2">一键自动化诊断引擎</h2>
                <p className="text-slate-500 text-sm">请输入业务标识，智能体将自动编排拨测工具，为您定位故障根因。</p>
            </div>

            <div className="w-full max-w-2xl bg-[#0f172a] border border-slate-800 rounded-3xl p-2 flex gap-2 shadow-2xl focus-within:border-indigo-500/50 transition-all">
                <input 
                    className="flex-1 bg-transparent px-6 py-4 text-white placeholder-slate-600 outline-none"
                    placeholder="请输入业务电路编号/客户名称..."
                    value={userInput}
                    onChange={e => setUserInput(e.target.value)}
                />
                <Button 
                    className="rounded-2xl px-8 bg-indigo-600 hover:bg-indigo-500 border-none"
                    onClick={() => handleStart('normal')}
                    disabled={!userInput.trim()}
                >
                    发起诊断
                </Button>
            </div>

            {/* 演示场景入口 */}
            <div className="space-y-4 w-full max-w-2xl">
                <div className="text-[10px] text-slate-600 uppercase font-bold tracking-widest text-center">演示快捷场景 (快速模拟真实故障流转)</div>
                <div className="grid grid-cols-3 gap-4">
                    <button onClick={() => handleStart('cut')} className="group flex flex-col items-center gap-3 p-5 bg-slate-900/40 border border-slate-800 rounded-3xl hover:border-red-500/50 hover:bg-red-500/5 transition-all">
                        <div className="w-12 h-12 rounded-2xl bg-red-500/10 text-red-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <XCircle size={24}/>
                        </div>
                        <div className="text-center">
                            <div className="text-sm font-bold text-white">物理层中断</div>
                            <div className="text-[10px] text-slate-500 mt-1">模拟光缆断裂场景</div>
                        </div>
                    </button>
                    <button onClick={() => handleStart('voice')} className="group flex flex-col items-center gap-3 p-5 bg-slate-900/40 border border-slate-800 rounded-3xl hover:border-emerald-500/50 hover:bg-emerald-500/5 transition-all">
                        <div className="w-12 h-12 rounded-2xl bg-emerald-500/10 text-emerald-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <Radio size={24}/>
                        </div>
                        <div className="text-center">
                            <div className="text-sm font-bold text-white">语音业务故障</div>
                            <div className="text-[10px] text-slate-500 mt-1">模拟网关/PBX异常</div>
                        </div>
                    </button>
                    <button onClick={() => handleStart('quality')} className="group flex flex-col items-center gap-3 p-5 bg-slate-900/40 border border-slate-800 rounded-3xl hover:border-amber-500/50 hover:bg-amber-500/5 transition-all">
                        <div className="w-12 h-12 rounded-2xl bg-amber-500/10 text-amber-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <TrendingDown size={24}/>
                        </div>
                        <div className="text-center">
                            <div className="text-sm font-bold text-white">质差流转流程</div>
                            <div className="text-[10px] text-slate-500 mt-1">模拟丢包跳转多维定界</div>
                        </div>
                    </button>
                </div>
            </div>
        </div>
      )}

      {(stage === 'processing' || stage === 'jump' || stage === 'conclusion') && (
        <div className="flex-1 flex overflow-hidden animate-in slide-in-from-right-10 duration-500">
            {/* Left Control Column */}
            <div className="w-80 border-r border-slate-800 p-6 flex flex-col bg-[#0f172a]/20">
                <div className="flex items-center justify-between mb-6">
                    <SectionTitle title="诊断任务流水线" className="mb-0" />
                    <button onClick={resetAll} className="p-1.5 hover:bg-slate-800 rounded text-slate-500 hover:text-white" title="重置诊断">
                        <ArrowLeft size={16}/>
                    </button>
                </div>

                <div className="space-y-5 flex-1">
                    {steps.map((step, idx) => (
                        <div key={step.id} className="relative pl-9">
                            <div className={`absolute left-0 top-0.5 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                                step.status === 'success' ? 'bg-emerald-500 border-emerald-500 text-white' : 
                                (step.status === 'processing' ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400 shadow-[0_0_10px_rgba(99,102,241,0.3)]' : 
                                (step.status === 'error' ? 'bg-red-500 border-red-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-600'))
                            }`}>
                                {step.status === 'success' ? <CheckCircle2 size={14}/> : (step.status === 'processing' ? <Loader2 size={14} className="animate-spin"/> : (step.status === 'error' ? <AlertCircle size={14}/> : <span className="text-xs">{idx+1}</span>))}
                            </div>
                            {idx < steps.length - 1 && <div className="absolute left-[11px] top-7 bottom-[-24px] w-[2px] bg-slate-800"></div>}

                            <div className="flex flex-col">
                                <span className={`text-xs font-bold ${step.status === 'processing' ? 'text-indigo-400' : (step.status === 'pending' ? 'text-slate-500' : 'text-slate-200')}`}>{step.name}</span>
                                {step.result && <span className={`text-[10px] mt-1 italic ${step.status === 'error' ? 'text-red-400' : 'text-slate-500'}`}>{step.result}</span>}
                            </div>
                        </div>
                    ))}
                </div>

                {/* 主动干预控制 */}
                {stage === 'processing' && (
                    <div className="mt-6 pt-6 border-t border-slate-800 grid grid-cols-2 gap-3">
                        <Button 
                            variant="secondary" 
                            size="sm" 
                            className="bg-slate-800 hover:bg-slate-700 border-none"
                            onClick={() => setIsPaused(!isPaused)}
                            icon={isPaused ? <Play size={14}/> : <Pause size={14}/>}
                        >
                            {isPaused ? '继续运行' : '暂停诊断'}
                        </Button>
                        <Button 
                            variant="secondary" 
                            size="sm" 
                            className="bg-slate-800 hover:bg-slate-700 border-none"
                            onClick={() => executeNextStep()}
                            disabled={isPaused}
                            icon={<SkipForward size={14}/>}
                        >
                            跳过步骤
                        </Button>
                    </div>
                )}

                <div className="mt-8 pt-6 border-t border-slate-800">
                    <div className="text-[10px] text-slate-500 uppercase font-black mb-4 tracking-widest">诊断目标上下文</div>
                    <div className="bg-[#020617] rounded-2xl p-4 space-y-3 border border-slate-800">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">客户名称</span>
                            <span className="text-[10px] text-slate-300 font-bold">{context.customer}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">业务类别</span>
                            <Badge color={context.bizType === '语音专线' ? 'green' : 'blue'} className="scale-75 origin-right">{context.bizType}</Badge>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] text-slate-500">实例 ID</span>
                            <span className="text-[10px] text-indigo-400 font-mono">{context.instanceId}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Evidence Area */}
            <div className="flex-1 p-10 overflow-y-auto custom-scrollbar flex flex-col gap-10">
                <div className="flex justify-between items-center">
                    <h2 className="text-2xl font-black text-white flex items-center gap-3">
                        <Database size={24} className="text-indigo-500" />
                        自动化证据链采集
                    </h2>
                    {(stage === 'conclusion' || stage === 'jump') && (
                        <Button size="sm" variant="secondary" onClick={resetAll} icon={<RefreshCcw size={14}/>}>重新诊断</Button>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-5">
                    {evidence.map((ev, i) => (
                        <div key={i} className="bg-slate-900/40 border border-slate-800 rounded-2xl p-6 hover:border-slate-700 transition-all group relative overflow-hidden">
                            <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                                <FileSearch size={40} className="text-white"/>
                            </div>
                            <div className="text-[10px] text-slate-500 font-black uppercase mb-2 group-hover:text-indigo-400 transition-colors tracking-widest">{ev.label}</div>
                            <div className="text-sm text-slate-200 leading-relaxed font-medium">{ev.value}</div>
                        </div>
                    ))}
                    {stage === 'processing' && (
                        <div className="col-span-2 py-10 flex flex-col items-center justify-center text-slate-700 border-2 border-dashed border-slate-800 rounded-3xl">
                            <Loader2 size={32} className="animate-spin mb-3 opacity-20"/>
                            <span className="text-sm font-medium">正在实时采集多源证据...</span>
                        </div>
                    )}
                </div>

                {stage === 'conclusion' && (
                    <div className="mt-auto bg-gradient-to-br from-indigo-950/40 to-slate-900 border border-indigo-500/30 rounded-3xl p-10 relative overflow-hidden animate-in zoom-in duration-500 shadow-2xl">
                        <div className="absolute top-0 right-0 p-10 opacity-5"><Sparkles size={100} className="text-indigo-500"/></div>
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-red-500 rounded-xl shadow-[0_0_15px_rgba(239,68,68,0.4)]">
                                <ShieldAlert size={24} className="text-white" />
                            </div>
                            <h3 className="text-xl font-black text-white tracking-tight">智能诊断结论</h3>
                        </div>
                        <p className="text-2xl font-bold text-indigo-50 text-left leading-snug mb-8">{conclusion}</p>

                        <div className="flex gap-4">
                            {evidenceValues.ping && (
                                <div className="bg-black/40 px-6 py-4 rounded-2xl border border-slate-800">
                                    <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-1">PING 丢包率</div>
                                    <div className="text-lg font-black text-red-400 font-mono">{evidenceValues.ping}</div>
                                </div>
                            )}
                            {evidenceValues.sip && (
                                <div className="bg-black/40 px-6 py-4 rounded-2xl border border-slate-800">
                                    <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-1">SIP 信令状态</div>
                                    <div className="text-lg font-black text-red-400 font-mono">{evidenceValues.sip}</div>
                                </div>
                            )}
                        </div>

                        <div className="mt-10 pt-8 border-t border-slate-800 flex justify-between items-center">
                            <div className="flex items-center gap-2 text-slate-500">
                                <AlertCircle size={14}/>
                                <span className="text-xs font-medium">结论基于全路径编排实测生成，置信度：98.4%</span>
                            </div>
                            <Button className="bg-indigo-600 hover:bg-indigo-500 border-none px-8 h-12 rounded-xl font-bold shadow-xl shadow-indigo-900/40">转入人工运维席位</Button>
                        </div>
                    </div>
                )}

                {stage === 'jump' && (
                    <div className="mt-auto bg-blue-900/10 border border-blue-500/30 rounded-3xl p-12 text-center space-y-8 animate-in slide-in-from-bottom-10 duration-700 shadow-2xl relative overflow-hidden">
                        <div className="absolute inset-0 bg-blue-500/5 animate-pulse"></div>
                        <div className="w-24 h-24 bg-blue-600/20 rounded-full flex items-center justify-center mx-auto ring-8 ring-blue-500/10 z-10 relative">
                            <ArrowRightLeft size={40} className="text-blue-400 animate-pulse" />
                        </div>
                        <div className="relative z-10">
                            <h3 className="text-3xl font-black text-white tracking-tight">已进入互联网业务多维定界流程</h3>
                            <p className="text-slate-400 mt-4 max-w-lg mx-auto leading-relaxed">系统检测到物理链路通畅但业务丢包。正在携带已采集的 12 项技术证据，自动跳转至业务定界分析系统...</p>
                        </div>
                        <div className="flex items-center justify-center gap-4 relative z-10">
                            <Loader2 size={20} className="animate-spin text-blue-500" />
                            <span className="text-xs text-blue-400 font-black tracking-[0.2em] uppercase">证据全量同步中: 物理/告警/SIP/配置快照</span>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

