          <button onClick={onClose} className="p-2 hover:bg-red-500/20 hover:text-red-400 rounded-md text-slate-400 transition-colors">
            <X size={18} />
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Navigation Rail */}
        <div className="w-20 md:w-56 border-r border-slate-800 bg-[#0f172a]/30 flex flex-col p-4 gap-2 shrink-0">
          <SectionTitle title="服务模式" className="mb-2 hidden md:flex" />
