import React, { useState, useRef, useEffect } from 'react';
import { 
    Send, Loader2, Bot, User, Headset, Sparkles, AlertCircle, 
    ArrowRight, History, Paperclip, Share2, Plus, MessageSquare,
    Trash2, ChevronLeft, Menu, ShieldCheck, Database, Activity, 
    Radio, Zap, Megaphone, Trash
} from 'lucide-react';
import { Button, Badge } from '../components/UI';
import { GoogleGenAI } from "@google/genai";
import { ChatMessage, ChatSession } from './types';
import { DiagnosisAgent } from './DiagnosisAgent';

export const ChatInterface: React.FC<{ isHuman: boolean }> = ({ isHuman: initialIsHuman }) => {
    const [isHuman, setIsHuman] = useState(initialIsHuman);
    const [showHistory, setShowHistory] = useState(true);
    const [activeDiagnosis, setActiveDiagnosis] = useState<boolean>(false);
    const [sessions, setSessions] = useState<ChatSession[]>([
        {
            id: 's1',
            title: '专线丢包故障诊断',
            lastMessage: '已定位至物理层异常。',
            timestamp: '10:20',
            messages: []
        },
        {
            id: 's2',
            title: '5G CPE 在线态核查',
            lastMessage: 'UUID: 5G-CPE-002',
            timestamp: '昨天',
            messages: []
        },
        {
            id: 's3',
            title: '智算中心 PUE 异常咨询',
            lastMessage: '能效指标已恢复正常。',
            timestamp: '2025-03-10',
            messages: []
        }
    ]);

    const [messages, setMessages] = useState<ChatMessage[]>([
        { 
            id: '1', 
            role: 'assistant', 
            content: '您好！我是您的智能运维管家。检测到您近期关注过“安徽省电力公司”的业务稳定性。您可以点击下方的快捷指令开始排查，或者直接向我描述问题。', 
            timestamp: new Date().toLocaleTimeString() 
        }
    ]);
    const [inputValue, setInputValue] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages, isLoading, activeDiagnosis]);

    const handleAction = (type: string) => {
        if (type === 'diagnosis') {
            setActiveDiagnosis(true);
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'system',
                content: '正在调起自动化诊断引擎...',
                timestamp: new Date().toLocaleTimeString()
            }]);
        } else if (type === 'human') {
            setIsHuman(true);
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'assistant',
                content: '好的，正在为您接通省公司二线专家：王工。当前前方排队 1 人，预计等待 1 分钟。',
                timestamp: new Date().toLocaleTimeString()
            }]);
        }
    };

    const handleSend = async () => {
        if (!inputValue.trim() || isLoading) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            content: inputValue,
            timestamp: new Date().toLocaleTimeString()
        };

        setMessages(prev => [...prev, userMsg]);
        setInputValue('');
        setIsLoading(true);

        try {
            if (isHuman) {
                setTimeout(() => {
                    setMessages(prev => [...prev, {
                        id: (Date.now()+1).toString(),
                        role: 'assistant',
                        content: '我是王工，已经收到您的反馈。正在核查该业务的历史告警日志。',
                        timestamp: new Date().toLocaleTimeString()
                    }]);
                    setIsLoading(false);
                }, 1500);
            } else {
                const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
                const response = await ai.models.generateContent({
                    model: 'gemini-3-flash-preview',
                    contents: `用户问题: "${inputValue}"。你是一个政企运维助手。请给出简洁的建议。`,
                });

                setMessages(prev => [...prev, {
                    id: (Date.now()+1).toString(),
                    role: 'assistant',
                    content: response.text || '暂无法处理。',
                    timestamp: new Date().toLocaleTimeString()
                }]);
                setIsLoading(false);
            }
        } catch (error) {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex-1 flex overflow-hidden">
            {/* Left: Chat History Sidebar (Internal) */}
            <div className={`bg-[#0f172a]/40 border-r border-slate-800 transition-all duration-300 flex flex-col overflow-hidden ${showHistory ? 'w-64' : 'w-0'}`}>
                <div className="p-4 border-b border-slate-800 flex justify-between items-center whitespace-nowrap">
                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest">历史会话</span>
                    <button onClick={() => setShowHistory(false)} className="p-1 hover:bg-slate-800 rounded text-slate-500 hover:text-white transition-colors">
                        <ChevronLeft size={16}/>
                    </button>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1 min-w-[250px]">
                    <button className="w-full flex items-center gap-2 p-3 mb-2 rounded-xl border border-dashed border-slate-700 text-slate-400 hover:text-white hover:border-indigo-500 transition-all text-xs font-bold">
                        <Plus size={14} /> 新会话
                    </button>
                    {sessions.map(s => (
                        <div key={s.id} className="group relative p-3 rounded-xl hover:bg-slate-800 cursor-pointer border border-transparent hover:border-slate-700 transition-all">
                            <div className="flex items-center gap-2 text-slate-300 mb-1">
                                <MessageSquare size={12} className="text-indigo-500" />
                                <span className="text-[11px] font-bold truncate">{s.title}</span>
                            </div>
                            <div className="text-[10px] text-slate-500 truncate pr-4">{s.lastMessage}</div>
                            <span className="absolute right-2 top-3 text-[9px] text-slate-600">{s.timestamp}</span>
                            <button className="absolute right-2 bottom-2 opacity-0 group-hover:opacity-100 p-1 text-slate-600 hover:text-red-400 transition-opacity">
                                <Trash size={10} />
                            </button>
                        </div>
                    ))}
                </div>
            </div>

            {/* Right: Main Chat Area */}
            <div className="flex-1 flex flex-col min-w-0 bg-[#020617]">
                {/* Internal Control Bar */}
                <div className="h-10 px-6 border-b border-slate-800 flex items-center justify-between bg-[#0f172a]/20 shrink-0">
                    <div className="flex items-center gap-4">
                         {!showHistory && (
                             <button onClick={() => setShowHistory(true)} className="flex items-center gap-1.5 text-slate-500 hover:text-indigo-400 transition-colors">
                                <History size={14} />
                                <span className="text-[10px] font-bold">展开历史</span>
                             </button>
                         )}
                         <div className="w-px h-3 bg-slate-800"></div>
                         <Badge color={isHuman ? 'green' : 'blue'} className="scale-75 origin-left">
                            {isHuman ? '人工二线席位' : 'AI 管家模式'}
                         </Badge>
                    </div>
                    <div className="text-[10px] text-slate-600 font-mono">CHANNEL_UP: 0x882B</div>
                </div>

                {/* Messages Display */}
                <div ref={scrollRef} className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-6">
                    {messages.map(msg => (
                        <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : (msg.role === 'system' ? 'justify-center' : 'justify-start')} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                            {msg.role === 'system' ? (
                                <div className="bg-slate-800/50 px-4 py-1.5 rounded-full text-[10px] text-slate-500 border border-slate-700 flex items-center gap-2">
                                    <Activity size={12} className="text-indigo-500" /> {msg.content}
                                </div>
                            ) : (
                                <div className={`flex gap-4 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                                    <div className={`w-9 h-9 rounded-xl flex items-center justify-center shrink-0 border ${msg.role === 'user' ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-800 border-slate-700 text-indigo-400'}`}>
                                        {msg.role === 'user' ? <User size={18} /> : (isHuman ? <Headset size={18} /> : <Bot size={18} />)}
                                    </div>
                                    <div className="space-y-1">
                                        <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-lg ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-[#1e293b] text-slate-200 border border-slate-700 rounded-tl-none'}`}>
                                            <div className="whitespace-pre-wrap">{msg.content}</div>
                                        </div>
                                        <div className={`text-[10px] text-slate-600 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>{msg.timestamp}</div>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}

                    {activeDiagnosis && (
                        <div className="animate-in zoom-in duration-500 bg-[#0f172a] border border-indigo-500/20 rounded-3xl overflow-hidden shadow-2xl">
                             <DiagnosisAgent 
                                embedded={true} 
                                onTransfer={(data) => {
                                    handleAction('human');
                                    setActiveDiagnosis(false);
                                }} 
                                onClose={() => setActiveDiagnosis(false)}
                             />
                        </div>
                    )}

                    {isLoading && (
                        <div className="flex justify-start">
                            <div className="flex gap-4 max-w-[85%]">
                                <div className="w-9 h-9 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center shrink-0">
                                    <Loader2 className="animate-spin text-indigo-500" size={18} />
                                </div>
                                <div className="bg-[#1e293b]/50 p-4 rounded-2xl rounded-tl-none border border-slate-800 flex gap-1 items-center h-10">
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Combined Input & Action Bar */}
                <div className="p-6 border-t border-slate-800 bg-[#0f172a]/30 shrink-0">
                    {/* Action Chips */}
                    {!activeDiagnosis && (
                        <div className="max-w-4xl mx-auto flex flex-wrap gap-2 mb-4">
                            <button onClick={() => handleAction('diagnosis')} className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-500/10 border border-indigo-500/30 rounded-full text-indigo-400 hover:bg-indigo-500 hover:text-white transition-all text-[11px] font-bold">
                                <Activity size={14}/> 中断一键体检
                            </button>
                            <button onClick={() => handleAction('human')} className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-500/10 border border-emerald-500/30 rounded-full text-emerald-400 hover:bg-emerald-500 hover:text-white transition-all text-[11px] font-bold">
                                <Headset size={14}/> 呼叫二线专家
                            </button>
                            <button className="flex items-center gap-1.5 px-3 py-1.5 bg-amber-500/10 border border-amber-500/30 rounded-full text-amber-400 hover:bg-amber-500 hover:text-white transition-all text-[11px] font-bold">
                                <Megaphone size={14}/> 最新维护公告
                            </button>
                            <button className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 border border-slate-700 rounded-full text-slate-400 hover:text-white transition-all text-[11px] font-bold">
                                <ShieldCheck size={14}/> 安全防护策略
                            </button>
                        </div>
                    )}

                    <div className="max-w-4xl mx-auto flex gap-4">
                        <div className="flex-1 relative group">
                            <div className="absolute left-3 top-1/2 -translate-y-1/2 flex items-center gap-2 opacity-50 group-focus-within:opacity-100 transition-opacity">
                                <button className="p-1 hover:text-indigo-400"><Paperclip size={16}/></button>
                            </div>
                            <input 
                                className="w-full bg-[#1e293b] border border-slate-700 rounded-2xl py-4 pl-12 pr-4 text-sm text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all shadow-inner"
                                placeholder={isHuman ? "告知王工您的详细故障情况..." : "输入问题或点击上方快捷标签..."}
                                value={inputValue}
                                onChange={e => setInputValue(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleSend()}
                            />
                        </div>
                        <Button 
                            onClick={handleSend} 
                            disabled={!inputValue.trim() || isLoading}
                            className="rounded-2xl w-14 h-14 p-0 bg-indigo-600 hover:bg-indigo-500 border-none shadow-xl shadow-indigo-900/40 shrink-0"
                        >
                            <Send size={20} />
                        </Button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, Search, Network, Zap, ShieldAlert, CheckCircle2, 
  AlertTriangle, Loader2, Send, ChevronRight, History, 
  Database, Radio, FileSearch, ArrowRightLeft, AlertCircle, Sparkles,
  Pause, Play, SkipForward, ArrowLeft, RefreshCcw, TrendingDown, X
} from 'lucide-react';
import { Button, Badge, SectionTitle, Input } from '../components/UI';
import { DiagnosisStep } from './types';

interface DiagnosisAgentProps {
  onTransfer: (data: any) => void;
  embedded?: boolean;
  onClose?: () => void;
}

export const DiagnosisAgent: React.FC<DiagnosisAgentProps> = ({ onTransfer, embedded = false, onClose }) => {
  const [stage, setStage] = useState<'input' | 'processing' | 'conclusion' | 'jump'>('input');
  const [isPaused, setIsPaused] = useState(false);
  const [simMode, setSimMode] = useState<'normal' | 'cut' | 'voice' | 'quality'>('normal');
  const [currentStepIdx, setCurrentStepIdx] = useState(-1);
  const [userInput, setUserInput] = useState('');
  const [context, setContext] = useState<any>({
    customer: '安徽省电力公司',
    bizType: '互联网专线',
    instanceId: 'AH-POWER-INET-001',
  });

  const [steps, setSteps] = useState<DiagnosisStep[]>([
    { id: '1', name: '运营商侧物理接口探测', status: 'pending' },
    { id: '2', name: '全路路径告警核查', status: 'pending' },
    { id: '3', name: '业务层面分流拨测 (ICMP/SIP)', status: 'pending' },
    { id: '4', name: '端到端性能快照导出', status: 'pending' }
  ]);

  const [evidence, setEvidence] = useState<any[]>([]);
  const [conclusion, setConclusion] = useState<string>('');
  const [evidenceValues, setEvidenceValues] = useState<any>({});

  // 核心控制逻辑
  useEffect(() => {
    let timer: any;
    if (stage === 'processing' && !isPaused && currentStepIdx < steps.length) {
        timer = setTimeout(() => {
            executeNextStep();
        }, 1500);
    }
    return () => clearTimeout(timer);
  }, [stage, isPaused, currentStepIdx]);

  const executeNextStep = async () => {
      const idx = currentStepIdx === -1 ? 0 : currentStepIdx;
      if (idx >= steps.length) return;

      const step = steps[idx];
      updateStep(step.id, 'processing');

      // 模拟每步逻辑
      if (idx === 0) {
          if (simMode === 'cut') {
              updateStep(step.id, 'error', '端口状态: DOWN (LOS告警)');
              finishDiagnosis('运营商侧外线物理中断。检测到物理层信号丢失，已自动派单至线路维保组。');
              return;
          }
          updateStep(step.id, 'success', '接口状态: NORMAL');
          addEvidence('接口探测', '上联端口 A/B 路负载均衡正常，未见物理翻转。');
      } else if (idx === 1) {
          updateStep(step.id, 'success', '全路告警核查完成');
          addEvidence('告警分析', '查得近1小时内无异常掉电或高阶路径LOS告警。');
      } else if (idx === 2) {
          if (context.bizType === '语音专线') {
              updateStep(step.id, 'error', '企业侧 PBX 拨测超时');
              setEvidenceValues({ sip: 'Auth Failed', gateway: 'Unreachable' });
              addEvidence('业务拨测', 'SIP 信令握手失败，对端网关 10.224.1.5 无响应。');
              finishDiagnosis('语音专线业务异常。定位为客户侧企业网关（PBX）宕机或配置丢失，请检查本地供电及配置态。');
              return;
          }
          // 互联网专线质量问题
          if (simMode === 'quality') {
              updateStep(step.id, 'success', 'PING 丢包率: 15%');
              setEvidenceValues({ ping: '15%', gateway: 'Normal' });
              addEvidence('质量拨测', '关键路径存在突发性丢包，物理链路通畅但业务质差。');
          } else {
              updateStep(step.id, 'success', '拨测正常');
              addEvidence('业务拨测', 'PING丢包率 0%，时延 8ms。');
          }
      } else if (idx === 3) {
          updateStep(step.id, 'success', '性能指标导出成功');
          addEvidence('性能快照', '光功率: -14.2dBm, 流量峰值: 45Mbps。');

          // 最后流转判断
          if (context.bizType === '互联网专线' && simMode === 'quality') {
              setStage('jump');
          } else {
              finishDiagnosis('业务运行基本正常。未发现明显故障根因，建议联系二线专家进行更深层次的数据流包头分析。');
          }
          return;
      }

      setCurrentStepIdx(idx + 1);
  };

  const handleStart = (mode: 'normal' | 'cut' | 'voice' | 'quality') => {
    setSimMode(mode);
    setContext({
        customer: mode === 'voice' ? '江淮汽车集团' : '安徽省电力公司',
        bizType: mode === 'voice' ? '语音专线' : '互联网专线',
        instanceId: mode === 'voice' ? 'JAC-VOICE-102' : 'AH-POWER-INET-001'
    });
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending', result: undefined })));
    setEvidence([]);
    setEvidenceValues({});
    setCurrentStepIdx(0);
    setStage('processing');
    setIsPaused(false);
  };

  const updateStep = (id: string, status: any, result?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, result } : s));
  };

  const addEvidence = (label: string, value: string) => {
    setEvidence(prev => [...prev, { label, value }]);
  };

  const finishDiagnosis = (msg: string) => {
    setConclusion(msg);
    setStage('conclusion');
  };

  const resetAll = () => {
    if (onClose) onClose();
    setStage('input');
    setSimMode('normal');
    setCurrentStepIdx(-1);
    setEvidence([]);
  };

  return (
    <div className={`flex-1 flex flex-col overflow-hidden ${embedded ? 'min-h-[450px] bg-[#020617]' : 'bg-[#020617]'}`}>
      {stage === 'input' && (
        <div className="flex-1 flex flex-col items-center justify-center p-6 space-y-6 animate-in fade-in zoom-in duration-500 relative">
            {embedded && (
                <button onClick={onClose} className="absolute top-4 right-4 p-2 text-slate-500 hover:text-white transition-colors"><X size={20}/></button>
            )}
            <div className="flex flex-col items-center">
                <div className="w-16 h-16 rounded-2xl bg-indigo-500/10 flex items-center justify-center border border-indigo-500/30 shadow-lg mb-4">
                    <Activity size={32} className="text-indigo-500 animate-pulse" />
                </div>
                <h2 className="text-xl font-black text-white">一键自动化诊断引擎</h2>
                <p className="text-slate-500 text-xs mt-1">智能编排多源拨测，即刻定位业务根因</p>
            </div>

            <div className="w-full max-w-lg bg-[#0f172a] border border-slate-800 rounded-2xl p-1.5 flex gap-2 shadow-2xl focus-within:border-indigo-500/50 transition-all">
                <input 
                    className="flex-1 bg-transparent px-4 py-2 text-sm text-white placeholder-slate-600 outline-none"
                    placeholder="输入业务标识或客户名称..."
                    value={userInput}
                    onChange={e => setUserInput(e.target.value)}
                />
                <Button 
                    className="rounded-xl px-6 bg-indigo-600 hover:bg-indigo-500 border-none h-10 text-xs font-bold"
                    onClick={() => handleStart('normal')}
                    disabled={!userInput.trim()}
                >
                    发起诊断
                </Button>
            </div>

            <div className="space-y-3 w-full max-w-lg">
                <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest text-center">快捷演示场景</div>
                <div className="grid grid-cols-3 gap-3">
                    <button onClick={() => handleStart('cut')} className="group flex flex-col items-center gap-2 p-4 bg-slate-900/40 border border-slate-800 rounded-2xl hover:border-red-500/50 hover:bg-red-500/5 transition-all text-center">
                        <div className="w-10 h-10 rounded-xl bg-red-500/10 text-red-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <AlertCircle size={20}/>
                        </div>
                        <div className="text-[10px] font-bold text-white">物理层中断</div>
                    </button>
                    <button onClick={() => handleStart('voice')} className="group flex flex-col items-center gap-2 p-4 bg-slate-900/40 border border-slate-800 rounded-2xl hover:border-emerald-500/50 hover:bg-emerald-500/5 transition-all text-center">
                        <div className="w-10 h-10 rounded-xl bg-emerald-500/10 text-emerald-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <Radio size={20}/>
                        </div>
                        <div className="text-[10px] font-bold text-white">语音业务故障</div>
                    </button>
                    <button onClick={() => handleStart('quality')} className="group flex flex-col items-center gap-2 p-4 bg-slate-900/40 border border-slate-800 rounded-2xl hover:border-amber-500/50 hover:bg-amber-500/5 transition-all text-center">
                        <div className="w-10 h-10 rounded-xl bg-amber-500/10 text-amber-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            <TrendingDown size={20}/>
                        </div>
                        <div className="text-[10px] font-bold text-white">丢包/质差</div>
                    </button>
                </div>
            </div>
        </div>
      )}

      {(stage === 'processing' || stage === 'jump' || stage === 'conclusion') && (
        <div className="flex-1 flex overflow-hidden animate-in slide-in-from-right-10 duration-500">
            {/* Left Control Column */}
            <div className={`w-64 border-r border-slate-800 p-6 flex flex-col bg-[#0f172a]/20 ${embedded ? 'hidden md:flex' : ''}`}>
                <div className="flex items-center justify-between mb-6">
                    <span className="text-[10px] text-slate-500 uppercase font-black tracking-widest">任务编排流水线</span>
                    <button onClick={resetAll} className="p-1.5 hover:bg-slate-800 rounded text-slate-500 hover:text-white" title="重置诊断">
                        <ArrowLeft size={16}/>
                    </button>
                </div>

                <div className="space-y-4 flex-1">
                    {steps.map((step, idx) => (
                        <div key={step.id} className="relative pl-8">
                            <div className={`absolute left-0 top-0.5 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all ${
                                step.status === 'success' ? 'bg-emerald-500 border-emerald-500 text-white' : 
                                (step.status === 'processing' ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 
                                (step.status === 'error' ? 'bg-red-500 border-red-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-600'))
                            }`}>
                                {step.status === 'success' ? <CheckCircle2 size={12}/> : (step.status === 'processing' ? <Loader2 size={12} className="animate-spin"/> : (step.status === 'error' ? <AlertCircle size={12}/> : <span className="text-[10px]">{idx+1}</span>))}
                            </div>
                            {idx < steps.length - 1 && <div className="absolute left-[10px] top-6 bottom-[-16px] w-[1px] bg-slate-800"></div>}

                            <div className="flex flex-col">
                                <span className={`text-[11px] font-bold ${step.status === 'processing' ? 'text-indigo-400' : (step.status === 'pending' ? 'text-slate-500' : 'text-slate-200')}`}>{step.name}</span>
                                {step.result && <span className={`text-[9px] mt-1 italic ${step.status === 'error' ? 'text-red-400' : 'text-slate-500'}`}>{step.result}</span>}
                            </div>
                        </div>
                    ))}
                </div>

                {stage === 'processing' && (
                    <div className="mt-6 pt-6 border-t border-slate-800 grid grid-cols-2 gap-3">
                        <Button 
                            variant="secondary" 
                            size="sm" 
                            className="bg-slate-800 hover:bg-slate-700 border-none h-8 text-[10px]"
                            onClick={() => setIsPaused(!isPaused)}
                            icon={isPaused ? <Play size={12}/> : <Pause size={12}/>}
                        >
                            {isPaused ? '运行' : '暂停'}
                        </Button>
                        <Button 
                            variant="secondary" 
                            size="sm" 
                            className="bg-slate-800 hover:bg-slate-700 border-none h-8 text-[10px]"
                            onClick={() => executeNextStep()}
                            disabled={isPaused}
                            icon={<SkipForward size={12}/>}
                        >
                            跳过
                        </Button>
                    </div>
                )}
            </div>

            {/* Right Evidence Area */}
            <div className="flex-1 p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
                <div className="flex justify-between items-center">
                    <h2 className="text-lg font-black text-white flex items-center gap-2">
                        <Database size={18} className="text-indigo-500" />
                        自动化证据链采集
                    </h2>
                    {(stage === 'conclusion' || stage === 'jump') && (
                        <Button size="sm" variant="secondary" onClick={resetAll} className="h-8 text-[10px]" icon={<RefreshCcw size={12}/>}>重新诊断</Button>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {evidence.map((ev, i) => (
                        <div key={i} className="bg-slate-900/40 border border-slate-800 rounded-2xl p-4 hover:border-slate-700 transition-all group relative overflow-hidden animate-in fade-in slide-in-from-left-4">
                            <div className="text-[9px] text-slate-500 font-black uppercase mb-1 tracking-widest">{ev.label}</div>
                            <div className="text-xs text-slate-200 leading-relaxed font-medium">{ev.value}</div>
                        </div>
                    ))}
                    {stage === 'processing' && (
                        <div className="col-span-1 md:col-span-2 py-6 flex flex-col items-center justify-center text-slate-700 border-2 border-dashed border-slate-800 rounded-2xl">
                            <Loader2 size={24} className="animate-spin mb-2 opacity-20"/>
                            <span className="text-xs font-medium">实时证据采集中...</span>
                        </div>
                    )}
                </div>

                {stage === 'conclusion' && (
                    <div className="mt-auto bg-gradient-to-br from-indigo-950/40 to-slate-900 border border-indigo-500/30 rounded-3xl p-6 relative overflow-hidden animate-in zoom-in duration-500 shadow-2xl">
                        <div className="absolute top-0 right-0 p-6 opacity-5"><Sparkles size={60} className="text-indigo-500"/></div>
                        <div className="flex items-center gap-2 mb-4">
                            <div className="p-1.5 bg-red-500 rounded-lg shadow-lg">
                                <ShieldAlert size={18} className="text-white" />
                            </div>
                            <h3 className="text-base font-black text-white tracking-tight">智能诊断结论</h3>
                        </div>
                        <p className="text-lg font-bold text-indigo-50 text-left leading-snug mb-6">{conclusion}</p>

                        <div className="flex gap-4">
                            {evidenceValues.ping && (
                                <div className="bg-black/40 px-4 py-3 rounded-xl border border-slate-800">
                                    <div className="text-[9px] text-slate-500 uppercase font-black mb-0.5">PING 丢包</div>
                                    <div className="text-base font-black text-red-400 font-mono">{evidenceValues.ping}</div>
                                </div>
                            )}
                            {evidenceValues.sip && (
                                <div className="bg-black/40 px-4 py-3 rounded-xl border border-slate-800">
                                    <div className="text-[9px] text-slate-500 uppercase font-black mb-0.5">SIP 状态</div>
                                    <div className="text-base font-black text-red-400 font-mono">{evidenceValues.sip}</div>
                                </div>
                            )}
                        </div>

                        <div className="mt-6 pt-4 border-t border-slate-800 flex justify-between items-center">
                            <div className="flex items-center gap-2 text-slate-500">
                                <AlertCircle size={12}/>
                                <span className="text-[10px] font-medium">置信度：98.4%</span>
                            </div>
                            <Button 
                              onClick={() => onTransfer({ context, evidence, conclusion })}
                              className="bg-indigo-600 hover:bg-indigo-500 border-none px-6 h-10 rounded-xl text-xs font-bold shadow-xl shadow-indigo-900/40"
                            >
                              转入人工专家席位
                            </Button>
                        </div>
                    </div>
                )}

                {stage === 'jump' && (
                    <div className="mt-auto bg-blue-900/10 border border-blue-500/30 rounded-2xl p-8 text-center space-y-4 animate-in slide-in-from-bottom-6 duration-700 shadow-2xl relative overflow-hidden">
                        <div className="w-16 h-16 bg-blue-600/20 rounded-full flex items-center justify-center mx-auto ring-4 ring-blue-500/10">
                            <ArrowRightLeft size={32} className="text-blue-400 animate-pulse" />
                        </div>
                        <h3 className="text-xl font-black text-white">进入互联网业务多维定界</h3>
                        <p className="text-slate-400 text-xs leading-relaxed">系统检测到业务质差。正在携带 12 项技术证据同步跳转至定界分析平台...</p>
                        <div className="flex items-center justify-center gap-2">
                            <Loader2 size={14} className="animate-spin text-blue-500" />
                            <span className="text-[9px] text-blue-400 font-black tracking-widest uppercase">证据同步中: 物理/告警/SIP</span>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
    Send, Loader2, Bot, User, Headset, Sparkles, AlertCircle, 
    ArrowRight, History, Paperclip, Share2, Plus, MessageSquare,
    Trash2, ChevronLeft, Menu, ShieldCheck, Database, Activity, 
    Radio, Zap, Megaphone, Trash, BarChart3, Fingerprint, Map, 
    ClipboardList, Info, Cpu, Globe
} from 'lucide-react';
import { Button, Badge } from '../components/UI';
import { GoogleGenAI } from "@google/genai";
import { ChatMessage, ChatSession } from './types';
import { DiagnosisAgent } from './DiagnosisAgent';

export const ChatInterface: React.FC<{ isHuman: boolean }> = ({ isHuman: initialIsHuman }) => {
    const [isHuman, setIsHuman] = useState(initialIsHuman);
    const [showHistory, setShowHistory] = useState(true);
    const [activeDiagnosis, setActiveDiagnosis] = useState<boolean>(false);

    // Mock Sessions with improved timestamps
    const [sessions, setSessions] = useState<ChatSession[]>([
        { id: 's1', title: '专线丢包故障诊断', lastMessage: '已定位至物理层异常。', timestamp: '10:20 AM', messages: [] },
        { id: 's2', title: '5G CPE 在线态核查', lastMessage: 'UUID: 5G-CPE-002', timestamp: 'Yesterday', messages: [] },
        { id: 's3', title: '智算中心 PUE 异常咨询', lastMessage: '能效指标已恢复正常。', timestamp: 'Mar 12', messages: [] },
        { id: 's4', title: 'SD-WAN 控制器证书更新', lastMessage: '证书已自动下发。', timestamp: 'Mar 10', messages: [] },
    ]);

    const [messages, setMessages] = useState<ChatMessage[]>([
        { 
            id: '1', 
            role: 'assistant', 
            content: '您好！我是您的智能运维管家。检测到您近期关注过“安徽省电力公司”的业务稳定性。您可以直接点击下方的快捷卡片或向我提问。', 
            timestamp: new Date().toLocaleTimeString() 
        }
    ]);
    const [inputValue, setInputValue] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages, isLoading, activeDiagnosis]);

    const handleAction = (type: string) => {
        if (type === 'diagnosis') {
            setActiveDiagnosis(true);
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'system',
                content: '正在调起自动化诊断引擎...',
                timestamp: new Date().toLocaleTimeString()
            }]);
        } else if (type === 'human') {
            setIsHuman(true);
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'assistant',
                content: '好的，正在为您接通省公司二线专家：王工。当前前方排队 1 人，预计等待 1 分钟。',
                timestamp: new Date().toLocaleTimeString()
            }]);
        }
    };

    const handleSend = async () => {
        if (!inputValue.trim() || isLoading) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            content: inputValue,
            timestamp: new Date().toLocaleTimeString()
        };

        setMessages(prev => [...prev, userMsg]);
        setInputValue('');
        setIsLoading(true);

        try {
            if (isHuman) {
                setTimeout(() => {
                    setMessages(prev => [...prev, {
                        id: (Date.now()+1).toString(),
                        role: 'assistant',
                        content: '我是王工，已经收到您的反馈。正在核查该业务的历史告警日志，请稍候。',
                        timestamp: new Date().toLocaleTimeString()
                    }]);
                    setIsLoading(false);
                }, 1500);
            } else {
                const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
                const response = await ai.models.generateContent({
                    model: 'gemini-3-flash-preview',
                    contents: `你是一个政企运维助手。用户问题: "${inputValue}"。请给出简洁的建议。如果是故障排查，建议用户点击下方的"体检"按钮。`,
                });

                setMessages(prev => [...prev, {
                    id: (Date.now()+1).toString(),
                    role: 'assistant',
                    content: response.text || '暂无法处理，请尝试转人工。',
                    timestamp: new Date().toLocaleTimeString()
                }]);
                setIsLoading(false);
            }
        } catch (error) {
            setIsLoading(false);
        }
    };

