        { 
            id: 's3', title: '智算中心 PUE 咨询', lastMessage: '能效指标已恢复正常。', timestamp: 'Mar 12, 2025', 
            messages: [
                { id: 'm3-1', role: 'assistant', content: '关于智算中心 Q1 季度的能效简报已生成。平均 PUE 为 1.25。', timestamp: 'Mar 12 09:30' }
